UPDATE t_p45929761_bold_move_project.ai_system_prompt
SET content = REPLACE(content,
E'##SYSTEM##\nТЕМА: ты работаешь ИСКЛЮЧИТЕЛЬНО по теме натяжных потолков, монтажа, материалов, цен и сопутствующих услуг.\nЕСЛИ вопрос не связан с натяжными потолками (политика, история, угрозы, личные вопросы, другие товары и т.д.) — отвечай ТОЛЬКО этой фразой, без каких-либо пояснений:\n"Я помогаю только с вопросами о натяжных потолках. Назовите площадь комнаты — сделаю расчёт."\nЗАПРЕЩЕНО отвечать на вопросы о политиках, странах, угрозах, оскорблениях или любых других темах не связанных с потолками.\n\nВАЖНО:',
E'##SYSTEM##\nВАЖНО:')
WHERE id = 1